// client/src/components/ResourceBar.js
import React from 'react';
import { useUser } from '../context/UserContext';
import { FishIcon, YarnIcon, EnergyIcon, CoinIcon } from './Icons';

const ResourceBar = () => {
  const { user } = useUser();

  if (!user) {
    return null;
  }

  return (
    <div className="fixed top-0 left-0 right-0 bg-white shadow-md py-2 px-4 z-10">
      <div className="flex justify-between">
        {/* Рыба (основная валюта) */}
        <div className="resource-container">
          <FishIcon className="resource-icon text-blue-500" />
          <span className="text-sm font-medium">{user.resources.fish}</span>
        </div>

        {/* Клубки шерсти */}
        <div className="resource-container">
          <YarnIcon className="resource-icon text-purple-500" />
          <span className="text-sm font-medium">{user.resources.yarnBalls}</span>
        </div>

        {/* Энергия */}
        <div className="resource-container">
          <EnergyIcon className="resource-icon text-yellow-500" />
          <span className="text-sm font-medium">{user.energy.current}/{user.energy.max}</span>
        </div>

        {/* Кошачьи монеты (премиум) */}
        <div className="resource-container">
          <CoinIcon className="resource-icon text-yellow-600" />
          <span className="text-sm font-medium">{user.resources.catCoins}</span>
        </div>
      </div>
    </div>
  );
};

export default ResourceBar;
